@import "tailwindcss";

/* Modal Portal Animations */
@keyframes modalFadeIn {
  from {
    opacity: 0;
    transform: scale(0.95) translateY(-20px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@keyframes backdropFadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

/* Modal Portal Classes */
.modal-portal-backdrop {
  animation: backdropFadeIn 0.2s ease-out forwards;
}

.animate-in {
  animation: modalFadeIn 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
}

/* Ensure modal is always on top and interactive */
#modal-root {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  z-index: 999999 !important;
  pointer-events: auto !important;
}

#modal-root:empty {
  display: none !important;
}

/* Page transition animations */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeOut {
  from {
    opacity: 1;
    transform: translateY(0);
  }
  to {
    opacity: 0;
    transform: translateY(-20px);
  }
}

@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translateX(30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.9) translateY(-20px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

/* Modal specific animations */
@keyframes modalEnter {
  from {
    opacity: 0;
    transform: scale(0.95) translateY(-10px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

/* Card hover animation */
@keyframes cardHover {
  from {
    transform: translateY(0);
    box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
  }
  to {
    transform: translateY(-5px);
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  }
}

/* Page transition classes */
.page-enter {
  animation: fadeIn 0.4s ease-out forwards;
}

.page-exit {
  animation: fadeOut 0.3s ease-in forwards;
}

.slide-in-right {
  animation: slideInRight 0.5s ease-out forwards;
}

.slide-in-left {
  animation: slideInLeft 0.5s ease-out forwards;
}

.slide-up {
  animation: slideUp 0.6s ease-out forwards;
}

.scale-in {
  animation: scaleIn 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
}

.modal-enter {
  animation: modalEnter 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
}

/* Card hover effect */
.card-hover {
  transition: all 0.3s ease;
}

.card-hover:hover {
  animation: cardHover 0.3s ease forwards;
}

/* Loading spinner animations */
@keyframes spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

@keyframes bounce {
  0%,
  100% {
    transform: translateY(-25%);
    animation-timing-function: cubic-bezier(0.8, 0, 1, 1);
  }
  50% {
    transform: none;
    animation-timing-function: cubic-bezier(0, 0, 0.2, 1);
  }
}

/* Progress bar animation */
@keyframes progressFill {
  from {
    width: 0%;
  }
  to {
    width: var(--progress);
  }
}

.progress-bar {
  animation: progressFill 0.3s ease-out forwards;
}

/* Button hover effects */
.btn-hover {
  transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

.btn-hover:hover {
  transform: translateY(-2px);
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.15);
}

/* Stagger animation for form elements */
.stagger-item {
  animation: slideUp 0.5s ease-out forwards;
  animation-delay: var(--stagger-delay, 0s);
}

.stagger-item:nth-child(1) { --stagger-delay: 0.1s; }
.stagger-item:nth-child(2) { --stagger-delay: 0.2s; }
.stagger-item:nth-child(3) { --stagger-delay: 0.3s; }
.stagger-item:nth-child(4) { --stagger-delay: 0.4s; }
.stagger-item:nth-child(5) { --stagger-delay: 0.5s; }
.stagger-item:nth-child(6) { --stagger-delay: 0.6s; }

/* Modal overlay styles */
.modal-overlay {
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

/* Smooth scrolling */
html {
  scroll-behavior: smooth;
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb {
  background: #c1c1c1;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #a8a8a8;
}

/* Focus states for accessibility */
button:focus,
a:focus,
input:focus,
textarea:focus,
select:focus {
  outline: 2px solid #3B82F6;
  outline-offset: 2px;
}

/* Mobile responsive improvements */
@media (max-width: 768px) {
  .btn-hover:hover {
    transform: translateY(-1px);
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.1);
  }

  .card-hover:hover {
    transform: none;
    animation: none;
  }

  .animate-in {
    animation: modalFadeIn 0.2s ease-out forwards;
  }
}

/* High contrast mode support */
@media (prefers-contrast: high) {
  .modal-backdrop {
    background-color: rgba(0, 0, 0, 0.8) !important;
  }
}

/* Reduced motion support */
@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .scroll-behavior {
    scroll-behavior: auto !important;
  }
}

@theme {
  --font-sans: "Inter", ui-sans-serif, system-ui, sans-serif,
    "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji";
}

html,
body {
  @apply bg-white dark:bg-gray-950;

  @media (prefers-color-scheme: dark) {
    color-scheme: dark;
  }
}

/* Custom animations for enhanced user experience */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translateX(30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.9);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes modalEnter {
  from {
    opacity: 0;
    transform: scale(0.95) translateY(10px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

/* Animation classes */
.animate-fade-in {
  animation: fadeIn 0.5s ease-out forwards;
}

.slide-in-left {
  animation: slideInLeft 0.6s ease-out forwards;
}

.slide-in-right {
  animation: slideInRight 0.6s ease-out forwards;
}

.slide-up {
  animation: slideUp 0.6s ease-out forwards;
}

.scale-in {
  animation: scaleIn 0.5s ease-out forwards;
}

.modal-enter {
  animation: modalEnter 0.3s ease-out forwards;
}

/* Stagger animation for items */
.stagger-item:nth-child(1) { animation-delay: 0.1s; }
.stagger-item:nth-child(2) { animation-delay: 0.2s; }
.stagger-item:nth-child(3) { animation-delay: 0.3s; }
.stagger-item:nth-child(4) { animation-delay: 0.4s; }
.stagger-item:nth-child(5) { animation-delay: 0.5s; }
.stagger-item:nth-child(6) { animation-delay: 0.6s; }
.stagger-item:nth-child(7) { animation-delay: 0.7s; }
.stagger-item:nth-child(8) { animation-delay: 0.8s; }

/* Button hover effects */
.btn-hover {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.btn-hover:hover {
  transform: translateY(-2px);
}

/* Card hover effects */
.card-hover {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.card-hover:hover {
  transform: translateY(-4px);
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
}

/* Floating action button effects */
.fab {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.fab:hover {
  transform: translateY(-3px) scale(1.05);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
}

/* Smooth scrolling */
html {
  scroll-behavior: smooth;
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: #f1f5f9;
}

::-webkit-scrollbar-thumb {
  background: #3b82f6;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #2563eb;
}

@import "tailwindcss";

/* Mobile-First Responsive Utilities */
@media (max-width: 768px) {
  /* Ensure text is readable on mobile */
  .mobile-text-scale {
    font-size: clamp(0.875rem, 2.5vw, 1rem);
    line-height: 1.5;
  }

  /* Mobile carousel touch improvements */
  .mobile-carousel-container {
    touch-action: pan-x pan-y;
    -webkit-overflow-scrolling: touch;
  }

  /* Mobile hero section improvements */
  .mobile-hero-padding {
    padding-left: 1rem;
    padding-right: 1rem;
    padding-top: 2rem;
    padding-bottom: 2rem;
  }

  /* Mobile button improvements */
  .mobile-button {
    min-height: 44px;
    touch-action: manipulation;
  }

  /* Mobile card spacing */
  .mobile-card-spacing {
    margin-bottom: 1rem;
    padding: 1rem;
  }

  /* Mobile Background Optimization */
  .mobile-bg-size {
    background-size: cover !important;
    background-position: center center !important;
    background-attachment: scroll !important;
  }

  /* Mobile Section Background Fix */
  .section-bg-mobile {
    background-size: 150% auto !important;
    background-position: center center !important;
    background-repeat: no-repeat !important;
  }

  /* Mobile Background Decorative Elements */
  .mobile-bg-decorative {
    transform: scale(0.6) !important;
    opacity: 0.3 !important;
  }

  /* Mobile Gradient Background */
  .mobile-gradient-fix {
    background-attachment: scroll !important;
    background-size: 100% 100% !important;
  }
}

/* Responsive Background Classes */
.responsive-bg-hero {
  background-size: cover;
  background-position: center center;
  background-attachment: fixed;
}

@media (max-width: 768px) {
  .responsive-bg-hero {
    background-size: cover;
    background-position: center center;
    background-attachment: scroll;
  }
}

.responsive-bg-section {
  background-size: cover;
  background-position: center center;
  background-repeat: no-repeat;
}

@media (max-width: 768px) {
  .responsive-bg-section {
    background-size: 120% auto;
    background-position: center center;
    background-repeat: no-repeat;
  }
}

/* Background Decorative Elements Responsive */
.bg-decoration {
  transition: transform 0.3s ease, opacity 0.3s ease;
}

@media (max-width: 768px) {
  .bg-decoration {
    transform: scale(0.7);
    opacity: 0.4;
  }
}

@media (max-width: 480px) {
  .bg-decoration {
    transform: scale(0.5);
    opacity: 0.3;
  }
}

/* Touch improvements for all devices */
.touch-friendly {
  touch-action: manipulation;
  -webkit-tap-highlight-color: transparent;
}

/* Mobile navigation improvements */
@media (max-width: 768px) {
  .mobile-nav-menu {
    position: fixed;
    top: 100%;
    left: 0;
    right: 0;
    background: rgba(255, 255, 255, 0.95);
    backdrop-filter: blur(10px);
    z-index: 50;
    transform: translateY(-100%);
    transition: transform 0.3s ease-in-out;
  }

  .mobile-nav-menu.open {
    transform: translateY(0);
  }
}

/* Modal Portal Animations */
@keyframes modalFadeIn {
